import flask
from prometheus_client import generate_latest, Counter, Gauge, Histogram
import time
import random

app = flask.Flask(__name__)

# --- Prometheus Metrics ---

# Counter for total requests
REQUEST_COUNT = Counter(
    'http_requests_total',
    'Total HTTP Requests',
    ['method', 'endpoint', 'status']
)

# Histogram for request duration
REQUEST_LATENCY = Histogram(
    'http_request_duration_seconds',
    'HTTP Request Latency',
    ['method', 'endpoint']
)

# Gauge for active requests (optional, but good for understanding concurrency)
# This one needs to be manually incremented/decremented
ACTIVE_REQUESTS = Gauge(
    'http_active_requests',
    'Number of active HTTP requests'
)

# --- Business Metrics Examples ---

# Counter for a specific business event, e.g., 'items processed'
PROCESSED_ITEMS_TOTAL = Counter(
    'app_processed_items_total',
    'Total number of items processed by the application',
    ['item_type']
)

# Gauge for a current state, e.g., 'queue size' or 'available resources'
CURRENT_QUEUE_SIZE = Gauge(
    'app_current_queue_size',
    'Current size of the processing queue'
)

# Histogram for a business process duration, e.g., 'database query time'
DB_QUERY_DURATION_SECONDS = Histogram(
    'app_db_query_duration_seconds',
    'Duration of database queries in seconds',
    ['query_type']
)

# --- Middleware for request tracking ---
@app.before_request
def before_request():
    flask.g.start_time = time.time()
    ACTIVE_REQUESTS.inc() # Increment active requests gauge

@app.after_request
def after_request(response):
    request_duration = time.time() - flask.g.start_time
    endpoint = flask.request.path
    method = flask.request.method
    status_code = response.status_code

    REQUEST_COUNT.labels(method, endpoint, status_code).inc()
    REQUEST_LATENCY.labels(method, endpoint).observe(request_duration)
    ACTIVE_REQUESTS.dec() # Decrement active requests gauge

    return response

# --- Application Routes ---

@app.route('/')
def home():
    # Simulate some work
    time.sleep(random.uniform(0.01, 0.1))

    # Example of incrementing a business counter
    if random.random() < 0.7:
        PROCESSED_ITEMS_TOTAL.labels('general').inc()
    else:
        PROCESSED_ITEMS_TOTAL.labels('special').inc()

    # Example of setting a business gauge
    CURRENT_QUEUE_SIZE.set(random.randint(0, 100))

    # Example of observing a business histogram
    with DB_QUERY_DURATION_SECONDS.labels('read').time():
        time.sleep(random.uniform(0.005, 0.05))

    return "Hello, Flask with Prometheus Metrics!"

@app.route('/slow')
def slow_endpoint():
    # Simulate a slower process
    time.sleep(random.uniform(0.2, 0.8))

    # Example of another business metric
    if random.random() < 0.5:
        PROCESSED_ITEMS_TOTAL.labels('heavy_task').inc()
    return "This was a slow endpoint."

@app.route('/error')
def error_endpoint():
    # Simulate an error response
    time.sleep(random.uniform(0.01, 0.05))
    flask.abort(500, description="Simulated Internal Server Error")
    # Note: after_request still fires, recording the 500 status.

# --- Prometheus Metrics Endpoint ---
@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': 'text/plain; version=0.0.4; charset=utf-8'}

if __name__ == '__main__':
    # Run the Flask app
    app.run(host='0.0.0.0', port=5000)